<template><div><PageHeader eyebrow="ADMIN / CONTENT" title="内容管理" description="维护作品、角色、人物和分类信息"/><el-tabs v-model="tab" @tab-change="load"><el-tab-pane label="作品" name="works"/><el-tab-pane label="角色" name="characters"/><el-tab-pane label="人物" name="persons"/><el-tab-pane label="分类" name="categories"/></el-tabs><div class="table-toolbar"><el-input v-if="tab!=='categories'" v-model="keyword" placeholder="搜索名称" clearable @keyup.enter="load"/><span v-else></span><el-button type="primary" @click="openCreate">新增{{ title }}</el-button></div><el-table v-loading="loading" :data="rows" stripe><el-table-column prop="id" label="ID" min-width="170"/><el-table-column :prop="tab==='works'?'title':'name'" label="名称" min-width="160"/><el-table-column v-if="tab==='works'" prop="status" label="状态"/><el-table-column v-if="tab==='characters'" prop="gender" label="性别"/><el-table-column v-if="tab==='persons'" prop="country" label="国家/地区"/><el-table-column label="操作" width="160"><template #default="{row}"><el-button size="small" @click="openEdit(row)">编辑</el-button><el-button size="small" type="danger" @click="remove(row)">删除</el-button></template></el-table-column></el-table><div v-if="tab!=='categories'" class="pagination-wrap"><el-pagination background :total="total" :page-size="10" v-model:current-page="current" @current-change="load"/></div><el-dialog v-model="dialog" :title="`${editing?'编辑':'新增'}${title}`" width="640"><el-form :model="form" label-position="top" class="form-grid"><template v-if="tab==='works'"><el-form-item label="标题"><el-input v-model="form.title"/></el-form-item><el-form-item label="状态"><el-input v-model="form.status" placeholder="ONGOING / COMPLETED"/></el-form-item><el-form-item label="上映日期"><el-date-picker v-model="form.releaseDate" value-format="YYYY-MM-DD"/></el-form-item><el-form-item label="封面地址"><el-input v-model="form.coverUrl"/></el-form-item><el-form-item label="简介" class="form-span"><el-input v-model="form.description" type="textarea" :rows="4"/></el-form-item></template><template v-if="tab==='characters'"><el-form-item label="名称"><el-input v-model="form.name"/></el-form-item><el-form-item label="性别"><el-input v-model="form.gender"/></el-form-item><el-form-item label="头像地址"><el-input v-model="form.avatarUrl"/></el-form-item><el-form-item label="简介" class="form-span"><el-input v-model="form.description" type="textarea" :rows="4"/></el-form-item></template><template v-if="tab==='persons'"><el-form-item label="姓名"><el-input v-model="form.name"/></el-form-item><el-form-item label="国家/地区"><el-input v-model="form.country"/></el-form-item><el-form-item label="生日"><el-date-picker v-model="form.birthday" value-format="YYYY-MM-DD"/></el-form-item><el-form-item label="头像地址"><el-input v-model="form.avatarUrl"/></el-form-item><el-form-item label="介绍" class="form-span"><el-input v-model="form.introduction" type="textarea" :rows="4"/></el-form-item></template><template v-if="tab==='categories'"><el-form-item label="分类名称" class="form-span"><el-input v-model="form.name"/></el-form-item></template></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import { computed,onMounted,reactive,ref } from 'vue';import { ElMessageBox } from 'element-plus';import PageHeader from '../../components/PageHeader.vue';import { workApi } from '../../api/work';import { characterApi } from '../../api/character';import { personApi } from '../../api/person';import { normalizePage } from '../../utils/page';const tab=ref('works'),keyword=ref(''),current=ref(1),loading=ref(false),rows=ref([]),total=ref(0),dialog=ref(false),editing=ref(false),form=reactive({});const title=computed(()=>({works:'作品',characters:'角色',persons:'人物',categories:'分类'}[tab.value]));function resetForm(data={}){Object.keys(form).forEach(k=>delete form[k]);Object.assign(form,JSON.parse(JSON.stringify(data)))}async function load(){loading.value=true;try{let data;if(tab.value==='works')data=keyword.value?await workApi.search({keyword:keyword.value,current:current.value,size:10}):await workApi.page({current:current.value,size:10});if(tab.value==='characters')data=keyword.value?await characterApi.search({keyword:keyword.value,current:current.value,size:10}):await characterApi.page({current:current.value,size:10});if(tab.value==='persons')data=keyword.value?await personApi.search({keyword:keyword.value,current:current.value,size:10}):await personApi.page({current:current.value,size:10});if(tab.value==='categories'){rows.value=await workApi.categories();total.value=rows.value.length}else{const p=normalizePage(data);rows.value=p.list;total.value=p.total}}finally{loading.value=false}}function openCreate(){editing.value=false;resetForm({});dialog.value=true}function openEdit(row){editing.value=true;resetForm(row);dialog.value=true}async function save(){const id=form.id;const data={...form};delete data.id;delete data.createdTime;delete data.updatedTime;delete data.isDeleted;if(tab.value==='works')editing.value?await workApi.update(id,data):await workApi.create(data);if(tab.value==='characters')editing.value?await characterApi.update(id,data):await characterApi.create(data);if(tab.value==='persons')editing.value?await personApi.update(id,data):await personApi.create(data);if(tab.value==='categories')editing.value?await workApi.updateCategory(id,data):await workApi.createCategory(data);dialog.value=false;load()}async function remove(row){await ElMessageBox.confirm(`确定删除${title.value}“${row.title||row.name}”吗？`);if(tab.value==='works')await workApi.remove(row.id);if(tab.value==='characters')await characterApi.remove(row.id);if(tab.value==='persons')await personApi.remove(row.id);if(tab.value==='categories')await workApi.removeCategory(row.id);load()}onMounted(load)</script>
